interface Operations extends Azure.ResourceManager.Operations {}

/** The provisioning state of the Employee resource. */
union EmployeeProvisioningState {
  string,
  ResourceProvisioningState,
}

/** The properties of an Employee resource. */
model EmployeeProperties {
  /** The age of the employee. */
  age?: int32;

  /** The city of the employee. */
  city?: string;

  /** The profile of the employee. */
  profile?: bytes;

  /** The provisioning state of the resource. */
  @visibility(Lifecycle.Read)
  provisioningState?: EmployeeProvisioningState;
}

/** An Employee resource. */
model Employee is TrackedResource<EmployeeProperties> {
  /** The name of the Employee resource. */
  @key("employeeName")
  @segment("employees")
  @pattern("^[a-zA-Z0-9-]{3,24}$")
  @path
  name: string;
}

@armResourceOperations
interface Employees {
  /** Get an Employee resource. */
  get is ArmResourceRead<Employee>;
  /** Create or update an Employee resource. */
  createOrUpdate is ArmResourceCreateOrReplaceAsync<Employee>;
  /** Update an Employee resource. */
  update is ArmResourcePatchSync<Employee, EmployeeProperties>;
  /** Delete an Employee resource. */
  delete is ArmResourceDeleteWithoutOkAsync<Employee>;
  /** List Employee resources by resource group. */
  listByResourceGroup is ArmResourceListByParent<Employee>;
  /** List Employee resources by subscription. */
  listBySubscription is ArmListBySubscription<Employee>;
}

