    $fileLines = [System.Collections.Generic.List[string]]::new([string[]][System.IO.File]::ReadAllLines($filePath))

    # Sort line numbers descending so insertions don't shift subsequent lines
    $sortedLineNums = $warningsByFile[$file].Keys | Sort-Object { [int]$_ } -Descending

    foreach ($lineNum in $sortedLineNums) {
        $codes = $warningsByFile[$file][$lineNum]
        $targetIdx = [int]$lineNum - 1  # 0-based index
        $targetLine = $fileLines[$targetIdx]

        # Determine indentation of target line
        if ($targetLine -match '^(\s*)') {
            $indent = $matches[1]
        } else {
            $indent = ''
        }

        # Check which suppress directives already exist above the target line
        $existingSuppresses = @()
        $checkIdx = $targetIdx - 1
        while ($checkIdx -ge 0 -and $fileLines[$checkIdx] -match '^\s*#suppress\s') {
            $existingSuppresses += $fileLines[$checkIdx]
            $checkIdx--
        }

        # Insert suppress directives for codes not already suppressed (in reverse order so first code ends up closest to target)
        $insertions = @()
        foreach ($code in $codes) {
            $alreadySuppressed = $false
            foreach ($existing in $existingSuppresses) {
                if ($existing -match [regex]::Escape($code)) {
                    $alreadySuppressed = $true
                    break
                }
            }
            if (-not $alreadySuppressed) {
                $insertions += "${indent}#suppress `"$code`" `"$justification`""
            }
        }

        if ($insertions.Count -gt 0) {
            # Insert right before the target line
            for ($i = $insertions.Count - 1; $i -ge 0; $i--) {
                $fileLines.Insert($targetIdx, $insertions[$i])
            }
        }
    }

    [System.IO.File]::WriteAllLines($filePath, $fileLines.ToArray())
    "Processed $file - inserted suppressions for $($sortedLineNums.Count) locations"
